<template>
    <div class="home">
        <div class="container flex">
            <div class="home-nav" v-if="device!='mobile'">
                <nav class="nav-list">
                    <a class="item" :key="index" 
                        :class="{'active': navIndex==index}" 
                        v-for="(item, index) in categories" 
                        @click="getArticle(item, index)">
                        <i class="anticon" :class="`icon-${item.icon}`"></i>
                        <span class="text">{{item.title}}</span>
                    </a>
                </nav>
            </div>

            <div class="home-content">
                <div class="articleList">
                    <div class="list-item block flex" v-for="(item, index) in articleList" :key="index">
                        <div class="media">
                            <a :href="item.url" target="_bank" v-lazy:background-image="item.images[0]"></a>
                        </div>
                        <div class="content">
                            <div class="desc">
                                <a :href="item.url">{{item.title}}</a>
                                <p>{{item.desc}}</p>
                            </div>
                            <div class="footer flex">
                                <div>作者：{{item.author}}</div>
                                <div v-if="device!='mobile'">{{item.createdAt}}</div>
                                <div><i class="anticon icon-eye"></i>{{item.views}}</div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <div class="home-aside" v-if="device!='mobile'">
                <div class="randomGirl">
                    <div class="media">
                        <a class="media-content" @click="getRandomGirl()" title="点我试试" target="_blank" v-lazy:background-image="randomGirl">
                            <span class="overlay"></span>
                        </a>
                        <div class="media-overlay">
                            <div class="flex">
                                <span class="day">{{ date.day }}</span>
                                <time class="year">{{ date.month }}月, {{ date.year }}</time>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
            
        </div>
    </div>
</template>
<script>
import { mapState } from 'vuex';
import { categories } from '@/core/data';
export default {
    data(){
        return{
            categories,
            navIndex: 0,
            articleList: [],
            page: 1,
            randomGirl: '',
            date: {
                year: '',
                month: '',
                day: ''
            }
        }
    },
    computed: {
        ...mapState({
            device: state => state.app.device
        })
    },
    mounted() {
        var item = {
            category: 'All',
            type: 'Girl'
        }
        this.getArticle(item, 0);
        this.getRandomGirl();
        this.getNowTime();
    },
    methods: {
        getArticle(item, index){
            if(this.navIndex != index){
                this.page = 1;
            }else{
                this.page++;
            }
            this.navIndex = index;
            this.axios.get(this.gankUrl+`/api/v2/data/category/${item.category}/type/${item.type}/page/${this.page}/count/10`).then((res) => {
                if(res.data.data){
                    console.log(res.data.data);
                    
                    this.articleList = res.data.data;
                }
            })
        },
        // 获取当前日期
        getNowTime(){
            var date = new Date();
            this.date.year = date.getFullYear();
            this.date.month = date.getMonth()+1;
            this.date.day = date.getDate();
        },
        // 随机图片，时间背景
        getRandomGirl(){
            this.axios.get(this.gankUrl+'/api/v2/random/category/Girl/type/Girl/count/1').then((res) => {
                if(res.data.data){
                    this.randomGirl = res.data.data[0].url;
                }
            })
        }
    }
}
</script>
<style lang="scss" scoped>
.home{
    position: relative;
    width: 100%;
    .container{
        padding-top: 50px;
        flex-direction: row;
        justify-content: space-between;
    }
    .home-nav{
        width: 160px;
        height: auto;
        margin-right: 15px;
        .nav-list{
            position: fixed;
            width: 160px;
            a.item{
                position: relative;
                display: block;
                cursor: pointer;
                height: 40px;
                line-height: 40px;
                font-weight: 700;
                padding: 0 15px;
                transition: color .1s;
                letter-spacing: .5px;
                margin-bottom: 15px;
                border-radius: 1px;
                width: 100%;
                i, .text{
                    @include font_color($font-color-light);
                }
                &.active{
                    background-color: $yellow;
                    i, .text{
                        color: $white;
                    }
                }
                &:hover{
                    background-color: $yellow;
                    transition: background .3s ease-in;
                    i, .text{
                        color: $white;
                        transition: color .1s ease-in;
                    }
                }
            }
        }
    }
    .home-content{
        position: relative;
        width: 595px;
        overflow: hidden;
        transition: none;
        .articleList{
            // @include bg_color($background-color-sub);
            .list-item{
                position: relative;
                flex-direction: row;
                word-wrap: break-word;
                margin: 15px 0;
                padding: 15px 10px;
                border-radius: 5px;
                &:first-child{
                    margin-top: 0;
                }
                &:last-child{
                    margin-bottom: 0;
                }
                .media{
                    position: relative;
                    display: block;
                    border-radius: 3px;
                    flex-shrink: 0;
                    align-items: flex-start;
                    overflow: hidden;
                    margin-right: 30px;
                    width: 33.33%;
                    a{
                        cursor: pointer;
                        @include font_color($font-color-light);
                        position: absolute;
                        top: 0;
                        bottom: 0;
                        left: 0;
                        right: 0;
                        border: 0;
                        border-radius: inherit;
                        background-size: cover;
                        background-repeat: no-repeat;
                        background-position: 50% 50%;
                        background-color: rgba(120, 120, 120, 0.1);
                    }
                    &::after{
                        content: '';
                        display: block;
                        padding-top: 66.66%;
                    }
                }
                .content{
                    display: flex;
                    flex-direction: column;
                    flex: 1 1 auto;
                    justify-content: center;
                    .desc{
                        flex: 1 1 auto;
                        a{
                            overflow: hidden;
                            display: -webkit-box;
                            -webkit-line-clamp: 2;
                            -webkit-box-orient: vertical;
                            @include font_color($font-color-light);
                            &:hover{
                                color: $yellow;
                            }
                        }
                        p{
                            font-size: $font_medium_s;
                            overflow: hidden;
                            display: -webkit-box;
                            -webkit-line-clamp: 2;
                            -webkit-box-orient: vertical;
                            margin-top: 1rem;
                            @include font_color($font-color-light);
                        }
                    }
                    .footer{
                        margin-top: 15px;
                        justify-content: space-between;
                        div{
                            font-size: $font_medium_s;
                            margin-right: 10px;
                            @include font_color($font-color-light);
                            i{
                                margin-right: 5px;
                                @include font_color($font-color-light);
                            }
                            &:last-child{
                                margin-right: 0;
                            }
                        }
                    }
                }
            }
        }
    }
    
    .home-aside{
        position: relative;
        display: block;
        width: 266px;
        margin-left: 15px;
    }

    .randomGirl{
        position: relative;
        border-radius: 3px;
        overflow: hidden;
        @include font_color($font-color-light);
        display: flex;
        flex-direction: column;
        word-wrap: break-word;
        width: 100%;
        .media{
            position: relative;
            display: block;
            overflow: hidden;
            border-radius: 3px;
            align-items: flex-start;
            flex-shrink: 0;
            .media-content{
                position: absolute;
                top: 0;
                bottom: 0;
                left: 0;
                right: 0;
                border: 0;
                cursor: pointer;
                border-radius: inherit;
                background-size: cover;
                background-repeat: no-repeat;
                background-position: 50% 50%;
                background-color: rgba(120, 120, 120, 0.1);
                color: #ffffff;
                .overlay{
                    width: 100%;
                    height: 100%;
                    background-color: rgba(0, 0, 0, 0.66);
                    position: absolute;
                    opacity: .22;
                    top: 0;
                    left: 0;
                    transition: opacity 0.3s ease-in-out;
                }
            }
            .media-overlay{
                position: absolute;
                top: 0;
                left: 0;
                right: 0;
                bottom: 0;
                padding: 0;
                z-index: 2;
                display: flex;
                bottom: auto;
                padding: 1.5rem;
                .flex{
                    font-family: nicetheme, Arial, sans-serif;
                    flex-direction: column;
                    .day{
                        color: #fff;
                        font-size: 3.5rem;
                        font-weight: 300;
                        line-height: 1;
                    }
                    .year{
                        font-size: 0.75rem;
                        color: #fff;
                        text-align: center;
                    }
                }
            }
            &::after{
                content: '';
                display: block;
                padding-top: 100%;
            }
        }
    }
}
@media screen and (max-width: 576px) {
    .home {
        .home-content{
            width: 100% !important;
            .media{
                margin-right: 20px !important;
            }
        }
    }
}
</style>


